数据处理工具类
提供数据清洗、转换和分析功能
"""

import pandas as pd
import numpy as np
from typing import List, Dict, Any, Optional, Union
from datetime import datetime
import re
import json


class DataProcessor:
    """数据处理工具类"""

    @staticmethod
    def clean_text(text: str) -> str:
        """清理文本"""
        if not isinstance(text, str):
            return ""

        # 去除多余空白
        text = re.sub(r'\\s+', ' ', text.strip())

        # 去除特殊字符（保留中文、英文、数字和基本标点）
        text = re.sub(r'[^\\w\\s\\u4e00-\\u9fff\\.,!?;:\\-\\[\\](){}"\'\\/]', '', text)

        return text

    @staticmethod
    def normalize_numbers(data: List[Union[int, float]]) -> List[float]:
        """数值归一化"""
        if not data:
            return []

        data_array = np.array(data, dtype=float)

        # 处理NaN和无穷大
        data_array = np.nan_to_num(data_array, nan=0.0, posinf=0.0, neginf=0.0)

        # 归一化到[0, 1]
        min_val = np.min(data_array)
        max_val = np.max(data_array)

        if max_val - min_val > 0:
            normalized = (data_array - min_val) / (max_val - min_val)
        else:
            normalized = np.zeros_like(data_array)

        return normalized.tolist()

    @staticmethod
    def detect_outliers(data: List[float], threshold: float = 3.0) -> List[bool]:
        """检测异常值（基于Z-score）"""
        if len(data) < 3:
            return [False] * len(data)

        data_array = np.array(data)
        mean = np.mean(data_array)
        std = np.std(data_array)

        if std == 0:
            return [False] * len(data)

        z_scores = np.abs((data_array - mean) / std)
        return (z_scores > threshold).tolist()

    @staticmethod
    def aggregate_data(data: List[Dict], group_by: str, agg_func: str = "mean") -> Dict:
        """数据聚合"""
        if not data:
            return {}

        # 转换为DataFrame
        df = pd.DataFrame(data)

        if group_by not in df.columns:
            raise ValueError(f"分组列 '{group_by}' 不存在")

        # 执行聚合
        if agg_func == "mean":
            result = df.groupby(group_by).mean()
        elif agg_func == "sum":
            result = df.groupby(group_by).sum()
        elif agg_func == "count":
            result = df.groupby(group_by).size()
        elif agg_func == "max":
            result = df.groupby(group_by).max()
        elif agg_func == "min":
            result = df.groupby(group_by).min()
        else:
            raise ValueError(f"不支持的聚合函数: {agg_func}")

        return result.to_dict()

    @staticmethod
    def convert_to_datetime(date_str: str, formats: List[str] = None) -> Optional[datetime]:
        """转换字符串为日期时间"""
        if formats is None:
            formats = [
                "%Y-%m-%d %H:%M:%S",
                "%Y/%m/%d %H:%M:%S",
                "%Y-%m-%d",
                "%Y/%m/%d",
                "%d/%m/%Y",
                "%m/%d/%Y"
            ]

        for fmt in formats:
            try:
                return datetime.strptime(date_str, fmt)
            except ValueError:
                continue

        return None

    @staticmethod
    def extract_features(text: str) -> Dict[str, Any]:
        """提取文本特征"""
        features = {
            "length": len(text),
            "word_count": len(text.split()),
            "has_numbers": bool(re.search(r'\\d', text)),
            "has_uppercase": bool(re.search(r'[A-Z]', text)),
            "has_special_chars": bool(re.search(r'[^\\w\\s]', text)),
            "sentence_count": len(re.split(r'[.!?]+', text)) - 1
        }

        return features


class DataValidator:
