    @staticmethod
    def validate_phone(phone: str) -> bool:
        """验证电话号码（中国）"""
        pattern = r'^1[3-9]\\d{9}$'
        return bool(re.match(pattern, phone))

    @staticmethod
    def validate_url(url: str) -> bool:
