        pattern = r'^https?:\\/\\/(?:www\\.)?[-a-zA-Z0-9@:%._\\+~#=]{1,256}\\.[a-zA-Z0-9()]{1,6}\\b(?:[-a-zA-Z0-9()@:%_\\+.~#?&\\/=]*)$'
        return bool(re.match(pattern, url))

    @staticmethod
    def validate_json(data: str) -> bool:
        """验证JSON格式"""
        try:
            json.loads(data)
            return True
        except:
            return False


