import random
import string
from typing import List, Dict, Any, Optional, Callable
from functools import wraps
from datetime import datetime, timedelta
import hashlib
import base64
import uuid


class StringUtils:
    """字符串工具类"""

    @staticmethod
    def generate_random_string(length: int = 10) -> str:
        """生成随机字符串"""
        chars = string.ascii_letters + string.digits
        return ''.join(random.choice(chars) for _ in range(length))

    @staticmethod
    def truncate_string(text: str, max_length: int, suffix: str = "...") -> str:
        """截断字符串"""
        if len(text) <= max_length:
            return text

        return text[:max_length - len(suffix)] + suffix

    @staticmethod
    def camel_to_snake(text: str) -> str:
        """驼峰转蛇形"""
        result = []
        for i, char in enumerate(text):
            if char.isupper() and i > 0:
                result.append('_')
            result.append(char.lower())
        return ''.join(result)

    @staticmethod
    def snake_to_camel(text: str) -> str:
        """蛇形转驼峰"""
        parts = text.split('_')
        return parts[0] + ''.join(part.capitalize() for part in parts[1:])


class TimeUtils:
    """时间工具类"""

    @staticmethod
    def get_timestamp() -> int:
        """获取当前时间戳（毫秒）"""
        return int(time.time() * 1000)

    @staticmethod
    def format_duration(seconds: float) -> str:
        """格式化持续时间"""
        if seconds < 1:
            return f"{seconds*1000:.0f}ms"
        elif seconds < 60:
            return f"{seconds:.1f}s"
        elif seconds < 3600:
            minutes = seconds // 60
            remaining = seconds % 60
            return f"{int(minutes)}m {int(remaining)}s"
        else:
            hours = seconds // 3600
            minutes = (seconds % 3600) // 60
            return f"{int(hours)}h {int(minutes)}m"

    @staticmethod
    def is_weekend(date: datetime = None) -> bool:
        """判断是否是周末"""
        if date is None:
            date = datetime.now()
        return date.weekday() >= 5

    @staticmethod
    def get_date_range(start_date: str, end_date: str, date_format: str = "%Y-%m-%d") -> List[str]:
        """获取日期范围"""
        start = datetime.strptime(start_date, date_format)
        end = datetime.strptime(end_date, date_format)

        dates = []
        current = start
        while current <= end:
            dates.append(current.strftime(date_format))
            current += timedelta(days=1)

        return dates


class SecurityUtils:
    """安全工具类"""

    @staticmethod
    def hash_password(password: str, salt: str = "") -> str:
        """哈希密码"""
        salted = password + salt
        return hashlib.sha256(salted.encode()).hexdigest()

    @staticmethod
    def generate_api_key() -> str:
        """生成API密钥"""
        random_bytes = os.urandom(32)
        return base64.urlsafe_b64encode(random_bytes).decode().rstrip('=')

    @staticmethod
    def generate_uuid() -> str:
        """生成UUID"""
        return str(uuid.uuid4())

    @staticmethod
    def mask_sensitive_data(data: str, visible_chars: int = 4) -> str:
        """掩码敏感数据"""
        if len(data) <= visible_chars * 2:
            return "*" * len(data)

        visible_start = data[:visible_chars]
        visible_end = data[-visible_chars:]
        masked_middle = "*" * (len(data) - visible_chars * 2)

        return visible_start + masked_middle + visible_end


def timer(func: Callable) -> Callable:
    """计时装饰器"""
    @wraps(func)
    def wrapper(*args, **kwargs):
        start_time = time.time()
        result = func(*args, **kwargs)
        end_time = time.time()

        duration = end_time - start_time
        print(f"函数 {func.__name__} 执行时间: {TimeUtils.format_duration(duration)}")

        return result
    return wrapper


def retry(max_attempts: int = 3, delay: float = 1.0, exceptions: tuple = (Exception,)):
    """重试装饰器"""
    def decorator(func: Callable) -> Callable:
        @wraps(func)
        def wrapper(*args, **kwargs):
            last_exception = None

            for attempt in range(max_attempts):
                try:
                    return func(*args, **kwargs)
                except exceptions as e:
                    last_exception = e

                    if attempt < max_attempts - 1:
                        sleep_time = delay * (2 ** attempt)  # 指数退避
                        print(f"尝试 {attempt + 1}/{max_attempts} 失败，{sleep_time:.1f}秒后重试: {e}")
                        time.sleep(sleep_time)
                    else:
                        print(f"所有 {max_attempts} 次尝试都失败了")
                        raise last_exception

            raise last_exception  # 永远不会执行到这里

        return wrapper
    return decorator


