from functools import wraps


@dataclass
class ApiResponse:
    """API响应封装"""
    success: bool
    data: Optional[Any] = None
    error: Optional[str] = None
    status_code: Optional[int] = None
    headers: Optional[Dict] = None
    elapsed_ms: Optional[int] = None


class ApiClient:
    """API客户端"""

    def __init__(self, base_url: str = "", timeout: int = 30):
        self.base_url = base_url.rstrip('/')
        self.timeout = timeout
        self.session = requests.Session()

        # 默认请求头
        self.session.headers.update({
            'User-Agent': 'OpenCode-API-Client/1.0',
            'Accept': 'application/json',
            'Content-Type': 'application/json'
        })

    def set_auth_token(self, token: str, auth_type: str = "Bearer"):
        """设置认证令牌"""
        self.session.headers['Authorization'] = f"{auth_type} {token}"

    def set_header(self, key: str, value: str):
        """设置请求头"""
        self.session.headers[key] = value

    def _make_request(self, method: str, endpoint: str, **kwargs) -> ApiResponse:
        """执行HTTP请求"""
        url = f"{self.base_url}/{endpoint.lstrip('/')}" if self.base_url else endpoint

        start_time = time.time()

        try:
            response = self.session.request(
                method=method,
                url=url,
                timeout=self.timeout,
                **kwargs
            )

            elapsed_ms = int((time.time() - start_time) * 1000)

            # 尝试解析JSON响应
            data = None
            if response.content:
                try:
                    data = response.json()
                except:
                    data = response.text

            return ApiResponse(
                success=200 <= response.status_code < 300,
                data=data,
                error=None if response.ok else f"HTTP {response.status_code}",
                status_code=response.status_code,
                headers=dict(response.headers),
                elapsed_ms=elapsed_ms
            )

        except requests.exceptions.Timeout:
            return ApiResponse(
                success=False,
                error=f"请求超时 ({self.timeout}s)",
                elapsed_ms=int((time.time() - start_time) * 1000)
            )
        except requests.exceptions.ConnectionError:
            return ApiResponse(
                success=False,
                error="连接错误"
            )
        except Exception as e:
            return ApiResponse(
                success=False,
                error=f"请求异常: {str(e)}"
            )

    def get(self, endpoint: str, params: Optional[Dict] = None, **kwargs) -> ApiResponse:
