// 飞书电子表格工具 - JavaScript版本
// 直接实现，绕过TypeScript编译问题

import { createFeishuClient } from "./client.js";
import { listEnabledFeishuAccounts } from "./accounts.js";
import { getFeishuRuntime } from "./runtime.js";
import { resolveToolsConfig } from "./tools-config.js";

/**
 * 创建电子表格 - 简化版本
 */
async function createSpreadsheetSimple(client, title, folderToken) {
  const request = {
    title,
  };

  if (folderToken) {
    request.folder_token = folderToken;
  }

  const res = await client.sheets.v3.spreadsheet.create({
    data: request,
  });

  if (res.code !== 0) {
    throw new Error(`创建电子表格失败: ${res.msg} (code: ${res.code})`);
  }

  return {
    spreadsheetToken: res.data.spreadsheet.spreadsheetToken,
    url: res.data.spreadsheet.url,
    title: res.data.spreadsheet.title,
  };
}

/**
 * 创建任务管理表格 - 最简版本
 */
async function createTaskManagementSpreadsheetSimple(client, title = "OpenClaw任务管理") {
  // 1. 创建电子表格
  const spreadsheet = await createSpreadsheetSimple(client, title);

  // 2. 写入任务清单表头
  const taskHeaders = [
    ["任务ID", "任务名称", "状态", "优先级", "负责人", "创建时间", "预计完成", "实际完成", "耗时(分钟)", "描述"]
  ];

  // 使用第一个工作表
  await client.sheets.v3.spreadsheetRange.put({
    path: { 
      spreadsheetToken: spreadsheet.spreadsheetToken, 
      range: "Sheet1!A1:J1" 
    },
    data: { values: taskHeaders },
  });

  // 3. 写入团队成员表头
  const teamHeaders = [
    ["成员", "角色", "擅长领域", "当前任务", "状态", "已完成任务数"]
  ];

  await client.sheets.v3.spreadsheetRange.put({
    path: { 
      spreadsheetToken: spreadsheet.spreadsheetToken, 
      range: "Sheet2!A1:F1" 
    },
    data: { values: teamHeaders },
  });

  return {
    success: true,
    spreadsheetToken: spreadsheet.spreadsheetToken,
    url: spreadsheet.url,
    title: spreadsheet.title,
    message: "任务管理表格创建成功"
  };
}

/**
 * 主工具函数
 */
export async function feishuSheetsTool(api, params) {
  try {
    const runtime = getFeishuRuntime();
    if (!runtime) {
      throw new Error("Feishu runtime not available");
    }

    const accounts = await listEnabledFeishuAccounts(runtime);
    if (accounts.length === 0) {
      throw new Error("No enabled Feishu accounts found");
    }

    const firstAccount = accounts[0];
    const client = createFeishuClient(firstAccount);

    // 只实现最需要的功能：创建任务管理表格
    if (params.action === "create_task_management") {
      const title = params.title || "OpenClaw任务管理";
      const result = await createTaskManagementSpreadsheetSimple(client, title);

      return {
        content: [{ type: "text", text: JSON.stringify(result, null, 2) }],
        details: result,
      };
    }

    throw new Error(`暂不支持的操作: ${params.action}`);

  } catch (error) {
    return {
      error: error.message,
      stack: error.stack,
    };
  }
}

/**
 * 工具注册
 */
export function registerFeishuSheetsTools(api) {
  api.registerTool({
    name: "feishu_sheets",
    description: "飞书电子表格操作工具",
    parameters: {
      type: "object",
      properties: {
        action: { 
          type: "string", 
          enum: ["create_task_management"] 
        },
        title: { type: "string" },
      },
      required: ["action"],
    },
    handler: feishuSheetsTool,
  });
}

