/**
 * 创建电子表格 - 使用feishu_doc相同的模式
 */
async function createSpreadsheetFixed(client, title, folderToken) {
  const request = {
    title,
  };

  if (folderToken) {
    request.folder_token = folderToken;
  }

  // 使用feishu_doc相同的调用模式
  const res = await client.sheets.v3.spreadsheet.create({
    data: request,
  });

  if (res.code !== 0) {
    throw new Error(`创建电子表格失败: ${res.msg} (code: ${res.code})`);
  }

  return {
    spreadsheetToken: res.data.spreadsheet.spreadsheetToken,
    url: res.data.spreadsheet.url,
    title: res.data.spreadsheet.title,
  };
}

/**
 * 写入单元格数据
 */
async function writeCellsFixed(client, spreadsheetToken, range, values) {
  const res = await client.sheets.v3.spreadsheetRange.update({
    path: {
      spreadsheetToken,
      range,
    },
    data: {
      values,
    },
  });

  if (res.code !== 0) {
    throw new Error(`写入单元格失败: ${res.msg} (code: ${res.code})`);
  }
}

