function writeToSheetV3(token, range, values) {
  return new Promise((resolve, reject) => {
    const [sheetId, cellRange] = range.includes('!') ? range.split('!') : ['', range];
    const apiRange = sheetId ? `${sheetId}!${cellRange}` : cellRange;

    const options = {
      hostname: 'open.feishu.cn',
      port: 443,
      path: `/open-apis/sheets/v3/spreadsheets/${spreadsheetToken}/range`,
      method: 'PUT',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${token}`,
      },
    };

    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => {
        data += chunk;
      });
      res.on('end', () => {
        try {
          const result = JSON.parse(data);
          resolve(result);
        } catch (error) {
          reject(error);
        }
      });
    });

    req.on('error', reject);

    // v3 API格式
    req.write(JSON.stringify({
      range: apiRange,
      values: values,
    }));

    req.end();
  });
}

