// 1. 获取token
async function getToken() {
  return new Promise((resolve) => {
    const options = {
      hostname: 'open.feishu.cn',
      port: 443,
      path: '/open-apis/auth/v3/tenant_access_token/internal',
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
    };

    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        const result = JSON.parse(data);
        resolve(result.tenant_access_token);
      });
    });

    req.write(JSON.stringify({ app_id: APP_ID, app_secret: APP_SECRET }));
    req.end();
  });
}

// 2. 创建表格（带重试）
async function createSpreadsheetWithRetry(token, retries = 3) {
  for (let i = 0; i < retries; i++) {
    console.log(`创建表格尝试 ${i + 1}/${retries}...`);

    const result = await new Promise((resolve) => {
      const options = {
        hostname: 'open.feishu.cn',
        port: 443,
        path: '/open-apis/sheets/v3/spreadsheets',
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        },
      };

      const req = https.request(options, (res) => {
        let data = '';
        res.on('data', (chunk) => data += chunk);
        res.on('end', () => {
          try {
            const json = JSON.parse(data);
            resolve(json);
          } catch (error) {
            resolve({ code: -1, msg: error.message });
          }
        });
      });

      req.on('error', (error) => {
        resolve({ code: -1, msg: error.message });
      });

      req.write(JSON.stringify({
        title: `工作看板-${new Date().toISOString().slice(0, 19).replace(/[:T]/g, '-')}`,
        folder_token: ""
      }));

      req.end();
    });

    if (result.code === 0 && result.data && result.data.spreadsheet) {
      const spreadsheet = result.data.spreadsheet;
      console.log(`✅ 表格创建成功: ${spreadsheet.title}`);
      console.log(`URL: ${spreadsheet.url}`);

      // 等待表格完全创建
      console.log('等待表格初始化...');
      await wait(3000);

      return spreadsheet;
    }

    console.log(`创建失败: ${result.msg}`);
    if (i < retries - 1) await wait(2000);
  }

  return null;
}

