  // 尝试不同的写入方法
  const methods = [
    { name: 'v2 values', path: `/open-apis/sheets/v2/spreadsheets/${spreadsheetToken}/values`, range: 'A1' },
    { name: 'v2 values Sheet1', path: `/open-apis/sheets/v2/spreadsheets/${spreadsheetToken}/values`, range: 'Sheet1!A1' },
    { name: 'v2 values 0', path: `/open-apis/sheets/v2/spreadsheets/${spreadsheetToken}/values`, range: '0!A1' },
  ];

  for (let attempt = 0; attempt < retries; attempt++) {
    console.log(`\n写入尝试 ${attempt + 1}/${retries}...`);

    for (const method of methods) {
      console.log(`尝试方法: ${method.name} (${method.range})`);

      const result = await new Promise((resolve) => {
        const options = {
          hostname: 'open.feishu.cn',
          port: 443,
          path: method.path,
          method: 'PUT',
          headers: {
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${token}`
          },
        };

        const req = https.request(options, (res) => {
          let data = '';
          res.on('data', (chunk) => data += chunk);
          res.on('end', () => {
            try {
              const json = JSON.parse(data);
              resolve(json);
            } catch (error) {
              resolve({ code: -1, msg: error.message });
            }
          });
        });

        req.on('error', (error) => {
          resolve({ code: -1, msg: error.message });
        });

        req.write(JSON.stringify({
          valueRange: {
            range: method.range,
            values: taskData
          }
        }));

        req.end();
      });

      console.log(`结果: code=${result.code}, msg=${result.msg}`);

      if (result.code === 0) {
        console.log(`✅ ${method.name} 成功!`);

        // 成功写入任务数据后，继续写入团队和统计
        console.log('继续写入团队数据...');
        await wait(1000);

        // 写入团队数据（使用相同的方法）
        const teamResult = await new Promise((resolve) => {
          const options = {
            hostname: 'open.feishu.cn',
            port: 443,
            path: method.path,
            method: 'PUT',
            headers: {
              'Content-Type': 'application/json',
              'Authorization': `Bearer ${token}`
            },
          };

          const req = https.request(options, (res) => {
            let data = '';
            res.on('data', (chunk) => data += chunk);
            res.on('end', () => {
              try {
                const json = JSON.parse(data);
                resolve(json);
              } catch (error) {
                resolve({ code: -1, msg: error.message });
              }
            });
          });

          req.write(JSON.stringify({
            valueRange: {
              range: method.range.replace('A1', 'A' + (taskData.length + 2)),
              values: teamData
            }
          }));

          req.end();
        });

        if (teamResult.code === 0) {
          console.log('✅ 团队数据写入成功');
        }

        return { success: true, method: method.name };
      }

      await wait(1000);
    }

    if (attempt < retries - 1) {
      console.log(`等待重试...`);
      await wait(3000);
    }
  }

  return { success: false };
}

