const https = require('https');
const fs = require('fs');

console.log('🔧 专注调试飞书Sheets API...\n');

// 配置
const zshrc = fs.readFileSync('/Users/mocklab/.zshrc', 'utf8');
const APP_ID = zshrc.match(/export FEISHU_APP_ID="([^"]+)"/)[1];
const APP_SECRET = zshrc.match(/export FEISHU_APP_SECRET="([^"]+)"/)[1];

// 获取token
async function getToken() {
  return new Promise((resolve) => {
    const options = {
      hostname: 'open.feishu.cn',
      port: 443,
      path: '/open-apis/auth/v3/tenant_access_token/internal',
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
    };

    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        const result = JSON.parse(data);
        resolve(result.tenant_access_token);
      });
    });

    req.write(JSON.stringify({ app_id: APP_ID, app_secret: APP_SECRET }));
    req.end();
  });
}

// 测试1: 创建表格并获取详细信息
async function testCreateAndGetDetails() {
  console.log('测试1: 创建表格并获取详细信息...\n');

  const token = await getToken();

  // 1. 创建表格
  const createResult = await new Promise((resolve) => {
    const options = {
      hostname: 'open.feishu.cn',
      port: 443,
      path: '/open-apis/sheets/v3/spreadsheets',
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${token}`
      },
    };

    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          resolve(json);
        } catch (error) {
          resolve({ code: -1, msg: error.message });
        }
      });
    });

    req.on('error', (error) => {
      resolve({ code: -1, msg: error.message });
    });

    req.write(JSON.stringify({
      title: `API测试-${Date.now()}`,
      folder_token: ""
    }));

    req.end();
  });

  console.log('创建结果:', JSON.stringify(createResult, null, 2));

  if (createResult.code !== 0 || !createResult.data?.spreadsheet) {
    console.log('❌ 表格创建失败');
    return;
  }

  const spreadsheet = createResult.data.spreadsheet;
  console.log('\n✅ 表格创建成功');
  console.log('标题:', spreadsheet.title);
  console.log('URL:', spreadsheet.url);
  console.log('完整响应中的spreadsheet对象:', JSON.stringify(spreadsheet, null, 2));

  // 等待一下
  await new Promise(resolve => setTimeout(resolve, 3000));

  // 2. 尝试获取表格元数据
  console.log('\n尝试获取表格元数据...');

  const metaResult = await new Promise((resolve) => {
    const options = {
      hostname: 'open.feishu.cn',
      port: 443,
      path: `/open-apis/sheets/v3/spreadsheets/${spreadsheet.spreadsheetToken}/metainfo`,
      method: 'GET',
      headers: {
        'Authorization': `Bearer ${token}`
      },
    };

    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          resolve(json);
        } catch (error) {
          resolve({ code: -1, msg: error.message });
        }
      });
    });

    req.on('error', (error) => {
      resolve({ code: -1, msg: error.message });
    });

    req.end();
  });

  console.log('元数据获取结果:', JSON.stringify(metaResult, null, 2));

  // 3. 尝试不同的写入方法
  console.log('\n测试不同的写入方法...');

  const testCases = [
    {
      name: 'v2 values (简单A1)',
      path: `/open-apis/sheets/v2/spreadsheets/${spreadsheet.spreadsheetToken}/values`,
      method: 'PUT',
      body: JSON.stringify({
        valueRange: {
          range: "A1",
          values: [["测试数据"]]
        }
      })
    },
    {
      name: 'v3 append',
      path: `/open-apis/sheets/v3/spreadsheets/${spreadsheet.spreadsheetToken}/values_append`,
      method: 'POST',
      body: JSON.stringify({
        range: "A1",
        values: [["测试数据"]]
      })
    },
    {
      name: 'v3 batch_update',
      path: `/open-apis/sheets/v3/spreadsheets/${spreadsheet.spreadsheetToken}/values_batch_update`,
      method: 'POST',
      body: JSON.stringify({
        valueRanges: [{
          range: "A1",
          values: [["测试数据"]]
        }]
      })
    }
  ];

  for (const testCase of testCases) {
    console.log(`\n测试: ${testCase.name}`);

    const result = await new Promise((resolve) => {
      const options = {
        hostname: 'open.feishu.cn',
        port: 443,
        path: testCase.path,
        method: testCase.method,
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        },
      };

      const req = https.request(options, (res) => {
        let data = '';
        res.on('data', (chunk) => data += chunk);
        res.on('end', () => {
          try {
            const json = JSON.parse(data);
            resolve(json);
          } catch (error) {
            resolve({ code: -1, msg: error.message });
          }
        });
      });

      req.on('error', (error) => {
        resolve({ code: -1, msg: error.message });
      });

      req.write(testCase.body);
      req.end();
    });

    console.log('结果:', JSON.stringify(result, null, 2));

    if (result.code === 0) {
      console.log(`✅ ${testCase.name} 成功!`);
      console.log('可用的API路径:', testCase.path);
      console.log('可用的请求体:', testCase.body);
      return { success: true, method: testCase.name, details: result };
    }
  }

  return { success: false };
}

// 测试2: 使用官方SDK的正确方法
async function testOfficialSDKMethod() {
  console.log('\n\n测试2: 使用官方SDK方法...\n');

  const token = await getToken();

  // 创建表格
  const createResult = await new Promise((resolve) => {
    const options = {
      hostname: 'open.feishu.cn',
      port: 443,
      path: '/open-apis/sheets/v3/spreadsheets',
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${token}`
      },
    };

    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          resolve(json);
        } catch (error) {
          resolve({ code: -1, msg: error.message });
        }
      });
    });

    req.on('error', (error) => {
      resolve({ code: -1, msg: error.message });
    });

    req.write(JSON.stringify({
      title: `SDK测试-${Date.now()}`,
      folder_token: ""
    }));

    req.end();
  });

  if (createResult.code !== 0) {
    console.log('创建失败:', createResult.msg);
    return;
  }

  const spreadsheetToken = createResult.data.spreadsheet.spreadsheetToken;
  console.log('表格Token:', spreadsheetToken);

  // 等待
  await new Promise(resolve => setTimeout(resolve, 3000));

  // 尝试官方文档中的方法
  console.log('\n尝试官方文档方法...');

  // 方法1: 使用sheetsBatchUpdate先添加工作表
  const batchUpdateResult = await new Promise((resolve) => {
    const options = {
      hostname: 'open.feishu.cn',
      port: 443,
      path: `/open-apis/sheets/v3/spreadsheets/${spreadsheetToken}/sheets_batch_update`,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${token}`
      },
    };

    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          resolve(json);
        } catch (error) {
          resolve({ code: -1, msg: error.message });
        }
      });
    });

    req.on('error', (error) => {
      resolve({ code: -1, msg: error.message });
    });

    req.write(JSON.stringify({
      requests: [
        {
          addSheet: {
            properties: {
              title: "Sheet1",
              index: 0
            }
          }
        }
      ]
    }));

    req.end();
  });

  console.log('批量更新结果:', JSON.stringify(batchUpdateResult, null, 2));

  if (batchUpdateResult.code === 0 && batchUpdateResult.data?.replies?.[0]?.addSheet) {
    const sheetId = batchUpdateResult.data.replies[0].addSheet.properties.sheetId;
    console.log('✅ 工作表创建成功, ID:', sheetId);

    // 现在尝试写入数据
    const writeResult = await new Promise((resolve) => {
      const options = {
        hostname: 'open.feishu.cn',
        port: 443,
        path: `/open-apis/sheets/v2/spreadsheets/${spreadsheetToken}/values`,
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        },
      };

      const req = https.request(options, (res) => {
        let data = '';
        res.on('data', (chunk) => data += chunk);
        res.on('end', () => {
          try {
            const json = JSON.parse(data);
            resolve(json);
          } catch (error) {
            resolve({ code: -1, msg: error.message });
          }
        });
      });

      req.on('error', (error) => {
        resolve({ code: -1, msg: error.message });
      });

      req.write(JSON.stringify({
        valueRange: {
          range: `${sheetId}!A1`,
          values: [["测试数据"]]
        }
      }));

      req.end();
    });

    console.log('写入结果:', JSON.stringify(writeResult, null, 2));

    if (writeResult.code === 0) {
      console.log('✅ API调通成功!');
      console.log('可用的方法:');
      console.log('1. 先创建表格');
      console.log('2. 使用sheets_batch_update添加工作表');
      console.log('3. 使用v2 values写入数据');
      console.log('4. range格式: {sheetId}!A1');
      return { success: true, method: '官方SDK方法' };
    }
  }

  return { success: false };
}

// 主函数
async function main() {
  console.log('开始调试飞书Sheets API...\n');

  try {
    // 测试1
    console.log('=== 测试1: 直接HTTP调用 ===');
    const result1 = await testCreateAndGetDetails();

    if (result1?.success) {
      console.log('\n🎉 测试1成功! 找到可用的API方法');
      return;
    }

    // 测试2
    console.log('\n\n=== 测试2: 官方SDK方法 ===');
    const result2 = await testOfficialSDKMethod();

    if (result2?.success) {
      console.log('\n🎉 测试2成功! 找到可用的API方法');
      return;
    }

    console.log('\n⚠️ 所有测试失败');
    console.log('需要:');
    console.log('1. 查看飞书官方API文档');
    console.log('2. 检查应用权限配置');
    console.log('3. 验证API调用参数');

  } catch (error) {
    console.log('\n❌ 调试错误:', error.message);
  }
}

// 执行
main();

