// 只检查API响应细节
const https = require('https');
const fs = require('fs');

console.log('🔍 检查API响应细节...\n');

// 配置
const zshrc = fs.readFileSync('/Users/mocklab/.zshrc', 'utf8');
const APP_ID = zshrc.match(/export FEISHU_APP_ID="([^"]+)"/)[1];
const APP_SECRET = zshrc.match(/export FEISHU_APP_SECRET="([^"]+)"/)[1];

// 获取token
async function getToken() {
  return new Promise((resolve) => {
    const options = {
      hostname: 'open.feishu.cn',
      port: 443,
      path: '/open-apis/auth/v3/tenant_access_token/internal',
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
    };

    const req = https.request(options, (res) => {
      let rawData = '';
      res.on('data', (chunk) => rawData += chunk);
      res.on('end', () => {
        console.log('Token响应状态:', res.statusCode);
        console.log('Token响应头:', JSON.stringify(res.headers, null, 2));
        console.log('Token响应原始数据:', rawData);

        try {
          const result = JSON.parse(rawData);
          resolve(result.tenant_access_token);
        } catch (error) {
          console.log('Token JSON解析错误:', error.message);
          resolve(null);
        }
      });
    });

    req.write(JSON.stringify({ app_id: APP_ID, app_secret: APP_SECRET }));
    req.end();
  });
}

// 测试创建表格API
async function testCreateAPI(token) {
  console.log('\n测试创建表格API...');

  return new Promise((resolve) => {
    const options = {
      hostname: 'open.feishu.cn',
      port: 443,
      path: '/open-apis/sheets/v3/spreadsheets',
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${token}`
      },
    };

    const req = https.request(options, (res) => {
      let rawData = '';
      res.on('data', (chunk) => rawData += chunk);
      res.on('end', () => {
        console.log('创建表格响应状态:', res.statusCode);
        console.log('创建表格响应头:', JSON.stringify(res.headers, null, 2));
        console.log('创建表格响应原始数据:', rawData);

        try {
          const result = JSON.parse(rawData);
          console.log('创建表格JSON解析成功');
          console.log('完整响应对象:', JSON.stringify(result, null, 2));

          if (result.code === 0 && result.data?.spreadsheet) {
            const spreadsheet = result.data.spreadsheet;
            console.log('\n📋 表格信息:');
            console.log('标题:', spreadsheet.title);
            console.log('URL:', spreadsheet.url);
            console.log('spreadsheet_token:', spreadsheet.spreadsheet_token);
            console.log('所有属性:', Object.keys(spreadsheet));

            // 检查属性名
            console.log('\n🔍 属性名检查:');
            console.log('有spreadsheetToken属性?', 'spreadsheetToken' in spreadsheet);
            console.log('有spreadsheet_token属性?', 'spreadsheet_token' in spreadsheet);
            console.log('实际属性:', Object.keys(spreadsheet).map(k => `"${k}"`).join(', '));
          }

          resolve(result);
        } catch (error) {
          console.log('创建表格JSON解析错误:', error.message);
          console.log('响应前100字符:', rawData.substring(0, 100));
          resolve(null);
        }
      });
    });

    req.on('error', (error) => {
      console.log('创建表格请求错误:', error.message);
      resolve(null);
    });

    req.write(JSON.stringify({
      title: `测试表格-${Date.now()}`,
      folder_token: ""
    }));

    req.end();
  });
}

// 测试v2 API
async function testV2API(token, spreadsheetToken) {
  console.log('\n测试v2 values API...');

  return new Promise((resolve) => {
    const options = {
      hostname: 'open.feishu.cn',
      port: 443,
      path: `/open-apis/sheets/v2/spreadsheets/${spreadsheetToken}/values`,
      method: 'PUT',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${token}`
      },
    };

    const req = https.request(options, (res) => {
      let rawData = '';
      res.on('data', (chunk) => rawData += chunk);
      res.on('end', () => {
        console.log('v2 API响应状态:', res.statusCode);
        console.log('v2 API响应头:', JSON.stringify(res.headers, null, 2));
        console.log('v2 API响应原始数据:', rawData);

        try {
          const result = JSON.parse(rawData);
          console.log('v2 API JSON解析成功:', JSON.stringify(result, null, 2));
          resolve(result);
        } catch (error) {
          console.log('v2 API JSON解析错误:', error.message);
          resolve(null);
        }
      });
    });

    req.on('error', (error) => {
      console.log('v2 API请求错误:', error.message);
      resolve(null);
    });

    req.write(JSON.stringify({
      valueRange: {
        range: "A1",
        values: [["测试数据"]]
      }
    }));

    req.end();
  });
}

// 主函数
async function main() {
  console.log('开始检查API响应...\n');

  const token = await getToken();
  if (!token) {
    console.log('❌ 无法获取token');
    return;
  }

  console.log('\n✅ Token获取成功:', token.substring(0, 20) + '...');

  // 测试创建表格
  const createResult = await testCreateAPI(token);

  if (createResult?.code === 0 && createResult.data?.spreadsheet) {
    const spreadsheet = createResult.data.spreadsheet;

    // 获取正确的token
    const spreadsheetToken = spreadsheet.spreadsheet_token || spreadsheet.spreadsheetToken;
    console.log('\n📌 获取到的spreadsheet_token:', spreadsheetToken);

    if (spreadsheetToken) {
      // 测试v2 API
      await testV2API(token, spreadsheetToken);
    } else {
      console.log('❌ 无法获取spreadsheet_token');
      console.log('完整spreadsheet对象:', JSON.stringify(spreadsheet, null, 2));
    }
  }

  console.log('\n🔍 问题分析:');
  console.log('1. 表格创建API工作正常');
  console.log('2. 问题可能在spreadsheet_token的获取');
  console.log('3. v2 API返回91402: NOTEXIST');
  console.log('4. 需要检查应用权限和表格状态');
