// 1. 获取token
async function getToken() {
  return new Promise((resolve) => {
    const options = {
      hostname: 'open.feishu.cn',
      port: 443,
      path: '/open-apis/auth/v3/tenant_access_token/internal',
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
    };

    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        const result = JSON.parse(data);
        resolve(result.tenant_access_token);
      });
    });

    req.write(JSON.stringify({ app_id: APP_ID, app_secret: APP_SECRET }));
    req.end();
  });
}

// 2. 创建表格
async function createSpreadsheet(token) {
  console.log('1. 创建表格...');

  const result = await new Promise((resolve) => {
    const options = {
      hostname: 'open.feishu.cn',
      port: 443,
      path: '/open-apis/sheets/v3/spreadsheets',
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${token}`
      },
    };

    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          resolve(json);
        } catch (error) {
          resolve({ code: -1, msg: error.message });
        }
      });
    });

    req.on('error', (error) => {
      resolve({ code: -1, msg: error.message });
    });

    req.write(JSON.stringify({
      title: `工作看板-${new Date().toISOString().slice(0, 10)}`,
      folder_token: ""
    }));

    req.end();
  });

  if (result.code === 0 && result.data?.spreadsheet) {
    const spreadsheet = result.data.spreadsheet;
    console.log(`✅ 表格创建成功: ${spreadsheet.title}`);
    console.log(`URL: ${spreadsheet.url}`);
    console.log(`Token: ${spreadsheet.spreadsheet_token}`);
    return spreadsheet;
  }

  console.log('❌ 表格创建失败:', result.msg);
  return null;
}

// 3. 添加工作表
async function addSheet(token, spreadsheetToken) {
  console.log('\n2. 添加工作表...');

  const result = await new Promise((resolve) => {
    const options = {
      hostname: 'open.feishu.cn',
      port: 443,
      path: `/open-apis/sheets/v3/spreadsheets/${spreadsheetToken}/sheets_batch_update`,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${token}`
      },
    };

    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          resolve(json);
        } catch (error) {
          resolve({ code: -1, msg: error.message });
        }
      });
    });

    req.on('error', (error) => {
      resolve({ code: -1, msg: error.message });
    });

    // 添加3个工作表
    req.write(JSON.stringify({
      requests: [
        {
          addSheet: {
            properties: {
              title: "任务清单",
              index: 0
            }
          }
        },
        {
          addSheet: {
            properties: {
              title: "团队成员",
              index: 1
            }
          }
        },
        {
          addSheet: {
            properties: {
              title: "统计看板",
              index: 2
            }
          }
        }
      ]
    }));

    req.end();
  });

  console.log('添加工作表结果:', JSON.stringify(result, null, 2));

  if (result.code === 0 && result.data?.replies) {
    const sheetIds = result.data.replies.map((reply, index) => ({
      title: ["任务清单", "团队成员", "统计看板"][index],
      sheetId: reply.addSheet?.properties?.sheetId
    }));

    console.log('✅ 工作表添加成功');
    sheetIds.forEach(sheet => {
      console.log(`  - ${sheet.title}: ${sheet.sheetId}`);
    });

    return sheetIds;
  }

  console.log('❌ 工作表添加失败:', result.msg);
  return null;
}

// 4. 写入数据到工作表
async function writeDataToSheet(token, spreadsheetToken, sheetId, title, data) {
  console.log(`\n写入数据到: ${title} (${sheetId})`);

  const result = await new Promise((resolve) => {
    const options = {
      hostname: 'open.feishu.cn',
      port: 443,
      path: `/open-apis/sheets/v2/spreadsheets/${spreadsheetToken}/values`,
      method: 'PUT',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${token}`
      },
    };

    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          resolve(json);
        } catch (error) {
          resolve({ code: -1, msg: error.message });
        }
      });
    });

    req.on('error', (error) => {
      resolve({ code: -1, msg: error.message });
    });

    // 使用sheetId!A1格式
    req.write(JSON.stringify({
      valueRange: {
        range: `${sheetId}!A1`,
        values: data
      }
    }));

    req.end();
  });

  console.log(`写入结果: code=${result.code}, msg=${result.msg}`);
  return result.code === 0;
}

