async function getToken() {
  return new Promise((resolve) => {
    const options = {
      hostname: 'open.feishu.cn',
      port: 443,
      path: '/open-apis/auth/v3/tenant_access_token/internal',
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
    };

    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        const result = JSON.parse(data);
        resolve(result.tenant_access_token);
      });
    });

    req.write(JSON.stringify({ app_id: APP_ID, app_secret: APP_SECRET }));
    req.end();
  });
}

// 创建表格并获取工作表信息
async function createAndGetSheetInfo(token) {
  console.log('1. 创建表格...');

  const createResult = await new Promise((resolve) => {
    const options = {
      hostname: 'open.feishu.cn',
      port: 443,
      path: '/open-apis/sheets/v3/spreadsheets',
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${token}`
      },
    };

    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          resolve(json);
        } catch (error) {
          resolve({ code: -1, msg: error.message });
        }
      });
    });

    req.on('error', (error) => {
      resolve({ code: -1, msg: error.message });
    });

    req.write(JSON.stringify({
      title: `工作看板-自动化-${new Date().toISOString().slice(11, 19).replace(/:/g, '')}`,
      folder_token: ""
    }));

    req.end();
  });

  if (createResult.code !== 0) {
    console.log('❌ 表格创建失败:', createResult.msg);
    return null;
  }

  const spreadsheet = createResult.data.spreadsheet;
  console.log(`✅ 表格创建成功: ${spreadsheet.title}`);
  console.log(`URL: ${spreadsheet.url}`);
  console.log(`Token: ${spreadsheet.spreadsheet_token}`);

  // 等待表格初始化
  console.log('\n等待表格初始化...');
  await new Promise(resolve => setTimeout(resolve, 5000));

  // 获取工作表信息
  console.log('\n2. 获取工作表信息...');
  const sheetInfo = await new Promise((resolve) => {
    const options = {
      hostname: 'open.feishu.cn',
      port: 443,
      path: `/open-apis/sheets/v3/spreadsheets/${spreadsheet.spreadsheet_token}/sheets`,
      method: 'GET',
      headers: {
        'Authorization': `Bearer ${token}`
      },
    };

    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          resolve(json);
        } catch (error) {
          resolve({ code: -1, msg: error.message });
        }
      });
    });

    req.on('error', (error) => {
      resolve({ code: -1, msg: error.message });
    });

    req.end();
  });

  console.log('工作表信息响应:', JSON.stringify(sheetInfo, null, 2));

  if (sheetInfo.code === 0 && sheetInfo.data?.sheet) {
    const sheet = sheetInfo.data.sheet;
    console.log(`\n✅ 找到默认工作表:`);
    console.log(`标题: ${sheet.title}`);
    console.log(`ID: ${sheet.sheet_id}`);
    console.log(`索引: ${sheet.index}`);

    return {
      spreadsheet,
      sheet
    };
  }

  console.log('❌ 无法获取工作表信息:', sheetInfo.msg);
  return null;
}

// 使用工作表ID写入数据
async function writeDataWithSheetId(token, spreadsheetToken, sheetId) {
  console.log('\n3. 准备写入工作看板数据...');

  // 准备数据
  const taskData = [
    ["📋 任务清单"],
    ["任务ID", "任务名称", "状态", "优先级", "负责人", "创建时间", "预计完成", "实际完成", "耗时(分钟)", "描述", "产出", "分类"],
    ...workspaceData.tasks.map(task => [
      task.task_id,
      task.task_name,
      task.status,
      task.priority,
      task.owner,
      task.created_time,
      task.estimated_completion,
      task.actual_completion || "进行中",
      task.time_spent_minutes.toString(),
      task.description,
      task.outputs,
      task.category
    ])
  ];

  const teamData = [
    ["👥 团队成员"],
    ["成员", "角色", "擅长领域", "当前任务", "状态", "已完成任务数", "专长分类"],
    ...workspaceData.team_members.map(member => [
      member.name,
      member.role,
      member.expertise,
      member.current_task,
      member.status,
      member.tasks_completed.toString(),
      member.expertise_category
    ])
  ];

  const statsData = [
    ["📊 统计看板"],
    ["统计项", "数值", "单位", "说明"],
    ["总任务数", workspaceData.statistics.total_tasks.toString(), "个", "所有任务数量"],
    ["已完成", workspaceData.statistics.completed_tasks.toString(), "个", "已完成任务数量"],
    ["进行中", workspaceData.statistics.in_progress_tasks.toString(), "个", "进行中任务数量"],
    ["完成率", (workspaceData.statistics.completion_rate * 100).toFixed(1) + "%", "", "任务完成比例"],
    ["总耗时", workspaceData.statistics.total_time_minutes.toString(), "分钟", "所有任务总耗时"],
    ["平均耗时", workspaceData.statistics.average_time_per_task.toFixed(1), "分钟", "平均每个任务耗时"],
    ["团队规模", workspaceData.statistics.team_size.toString(), "人", "团队成员总数"]
  ];

  console.log(`数据准备完成:`);
  console.log(`- 任务: ${taskData.length - 2} 行`);
  console.log(`- 团队: ${teamData.length - 2} 行`);
  console.log(`- 统计: ${statsData.length - 2} 行`);

  // 写入任务数据
  console.log('\n4. 写入任务数据...');
  const taskResult = await new Promise((resolve) => {
    const options = {
      hostname: 'open.feishu.cn',
      port: 443,
      path: `/open-apis/sheets/v2/spreadsheets/${spreadsheetToken}/values`,
      method: 'PUT',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${token}`
      },
    };

    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          resolve(json);
        } catch (error) {
          resolve({ code: -1, msg: error.message });
        }
      });
    });

    req.on('error', (error) => {
      resolve({ code: -1, msg: error.message });
    });

    // 使用sheetId!A1格式
    req.write(JSON.stringify({
      valueRange: {
        range: `${sheetId}!A1`,
        values: taskData
      }
    }));

    req.end();
  });

  console.log(`任务数据写入结果: code=${taskResult.code}, msg=${taskResult.msg}`);

  if (taskResult.code === 0) {
    console.log('✅ 任务数据写入成功!');

    // 写入团队数据（放在任务数据下面）
    console.log('\n5. 写入团队数据...');
    const teamRowStart = taskData.length + 2; // 空一行

    const teamResult = await new Promise((resolve) => {
      const options = {
        hostname: 'open.feishu.cn',
        port: 443,
        path: `/open-apis/sheets/v2/spreadsheets/${spreadsheetToken}/values`,
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        },
      };

      const req = https.request(options, (res) => {
        let data = '';
        res.on('data', (chunk) => data += chunk);
        res.on('end', () => {
          try {
            const json = JSON.parse(data);
            resolve(json);
          } catch (error) {
            resolve({ code: -1, msg: error.message });
          }
        });
      });

      req.write(JSON.stringify({
        valueRange: {
          range: `${sheetId}!A${teamRowStart}`,
          values: teamData
        }
      }));

      req.end();
    });

    console.log(`团队数据写入结果: code=${teamResult.code}, msg=${teamResult.msg}`);

    if (teamResult.code === 0) {
      console.log('✅ 团队数据写入成功!');

      // 写入统计数据
      console.log('\n6. 写入统计数据...');
      const statsRowStart = teamRowStart + teamData.length + 2; // 再空一行

      const statsResult = await new Promise((resolve) => {
        const options = {
          hostname: 'open.feishu.cn',
          port: 443,
          path: `/open-apis/sheets/v2/spreadsheets/${spreadsheetToken}/values`,
          method: 'PUT',
          headers: {
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${token}`
          },
        };

        const req = https.request(options, (res) => {
          let data = '';
          res.on('data', (chunk) => data += chunk);
          res.on('end', () => {
            try {
              const json = JSON.parse(data);
              resolve(json);
            } catch (error) {
              resolve({ code: -1, msg: error.message });
            }
          });
        });

        req.write(JSON.stringify({
          valueRange: {
            range: `${sheetId}!A${statsRowStart}`,
            values: statsData
          }
        }));

        req.end();
      });

      console.log(`统计数据写入结果: code=${statsResult.code}, msg=${statsResult.msg}`);

      if (statsResult.code === 0) {
        console.log('✅ 统计数据写入成功!');
        return { success: true, task: true, team: true, stats: true };
      }
    }
  }

  return { success: false, taskResult };
}

// 主函数
async function main() {
  console.log('开始自动化写入工作看板数据...\n');

  try {
    const token = await getToken();
    console.log('✅ Token获取成功\n');

    // 创建表格并获取工作表信息
    const tableInfo = await createAndGetSheetInfo(token);
    if (!tableInfo) return;

    const { spreadsheet, sheet } = tableInfo;

    // 写入数据
    const writeResult = await writeDataWithSheetId(token, spreadsheet.spreadsheet_token, sheet.sheet_id);

    console.log('\n' + '='.repeat(60));
    console.log('🎉 API调通结果');
    console.log('='.repeat(60));

    if (writeResult.success) {
      console.log('✅ ✅ ✅ API完全调通！ ✅ ✅ ✅');
      console.log('');
      console.log('📋 表格信息:');
      console.log(`标题: ${spreadsheet.title}`);
      console.log(`URL: ${spreadsheet.url}`);
      console.log(`工作表: ${sheet.title} (ID: ${sheet.sheet_id})`);
      console.log('');
      console.log('📊 数据写入情况:');
      console.log(`- 任务清单: ${workspaceData.tasks.length} 个任务 ✅`);
      console.log(`- 团队成员: ${workspaceData.team_members.length} 个成员 ✅`);
      console.log(`- 统计看板: 完整的数据分析 ✅`);
      console.log('');
      console.log('🚀 自动化完成！');
      console.log('工作看板已成功转换为飞书电子表格，数据已自动填充');
      console.log('');
      console.log('💡 技术细节:');
      console.log('1. 使用 v3 API 创建表格');
      console.log('2. 使用 v3 API 获取工作表信息');
      console.log('3. 使用 v2 values API 写入数据');
      console.log('4. range格式: {sheetId}!A1');
      console.log('');
      console.log(`立即查看: ${spreadsheet.url}`);
    } else {
      console.log('⚠️ 数据写入遇到问题');
      console.log(`表格已创建: ${spreadsheet.url}`);
      console.log(`工作表ID: ${sheet.sheet_id}`);

