console.log('\n🎯 下一步:');
console.log('1. 创建多维表格应用');
console.log('2. 设计数据表结构');
console.log('3. 插入工作看板数据');
console.log('4. 验证自动化成功');

// 直接调用飞书Bitable API创建多维表格
const https = require('https');
const fs = require('fs');

console.log('🚀 直接调用飞书Bitable API创建多维表格...\n');

// 配置
const zshrc = fs.readFileSync('/Users/mocklab/.zshrc', 'utf8');
const APP_ID = zshrc.match(/export FEISHU_APP_ID="([^"]+)"/)[1];
const APP_SECRET = zshrc.match(/export FEISHU_APP_SECRET="([^"]+)"/)[1];

// 工作看板数据
const workspaceData = JSON.parse(fs.readFileSync('/Users/mocklab/.openclaw/workspace/task-management/data-for-sheets.json', 'utf8'));

// 1. 获取token
function getToken() {
  return new Promise((resolve) => {
    const options = {
      hostname: 'open.feishu.cn',
      port: 443,
      path: '/open-apis/auth/v3/tenant_access_token/internal',
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
    };

    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        const result = JSON.parse(data);
        resolve(result.tenant_access_token);
      });
    });

    req.write(JSON.stringify({ app_id: APP_ID, app_secret: APP_SECRET }));
    req.end();
  });
}

// 2. 创建Bitable应用
async function createBitableApp(token, name) {
  console.log(`创建多维表格: ${name}`);

  return new Promise((resolve) => {
    const options = {
      hostname: 'open.feishu.cn',
      port: 443,
      path: '/open-apis/bitable/v1/apps',
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${token}`
      },
    };

    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          console.log(`创建结果: code=${json.code}, msg=${json.msg}`);

          if (json.code === 0 && json.data && json.data.app) {
            const app = json.data.app;
            console.log('✅ 多维表格创建成功!');
            console.log(`名称: ${app.name}`);
            console.log(`App Token: ${app.app_token}`);
            console.log(`URL: ${app.url}`);
            resolve({ success: true, app });
          } else {
            console.log('❌ 创建失败:', json.msg);
            resolve({ success: false, error: json.msg });
          }
        } catch (error) {
          console.log('❌ JSON解析失败:', error.message);
          console.log('响应:', data);
          resolve({ success: false, error: error.message });
        }
      });
    });

    req.on('error', (error) => {
      console.log('❌ 请求错误:', error.message);
      resolve({ success: false, error: error.message });
    });

    req.write(JSON.stringify({ name }));
    req.end();
  });
}

// 3. 获取表格列表
async function getTables(token, appToken) {
  console.log(`\n获取表格列表...`);

  return new Promise((resolve) => {
    const options = {
      hostname: 'open.feishu.cn',
      port: 443,
      path: `/open-apis/bitable/v1/apps/${appToken}/tables`,
      method: 'GET',
      headers: {
        'Authorization': `Bearer ${token}`
      },
    };

    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          if (json.code === 0 && json.data && json.data.items) {
            console.log(`找到 ${json.data.items.length} 个表格:`);
            json.data.items.forEach((table, index) => {
              console.log(`  ${index}. ${table.name} (ID: ${table.table_id})`);
            });
            resolve({ success: true, tables: json.data.items });
          } else {
            console.log('获取表格失败:', json.msg);
            resolve({ success: false, error: json.msg });
          }
        } catch (error) {
          console.log('JSON解析失败:', error.message);
          resolve({ success: false, error: error.message });
        }
      });
    });

    req.on('error', (error) => {
      console.log('请求错误:', error.message);
      resolve({ success: false, error: error.message });
    });

    req.end();
  });
}

// 4. 创建字段
async function createField(token, appToken, tableId, fieldName, fieldType, property) {
  console.log(`创建字段: ${fieldName} (类型: ${fieldType})`);

  return new Promise((resolve) => {
    const options = {
      hostname: 'open.feishu.cn',
      port: 443,
      path: `/open-apis/bitable/v1/apps/${appToken}/tables/${tableId}/fields`,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${token}`
      },
    };

    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          if (json.code === 0 && json.data && json.data.field) {
            console.log(`✅ 字段创建成功: ${fieldName}`);
            resolve({ success: true, field: json.data.field });
          } else {
            console.log(`❌ 字段创建失败: ${json.msg}`);
            resolve({ success: false, error: json.msg });
          }
        } catch (error) {
          console.log('JSON解析失败:', error.message);
          resolve({ success: false, error: error.message });
        }
      });
    });

    req.on('error', (error) => {
      console.log('请求错误:', error.message);
      resolve({ success: false, error: error.message });
    });

    const requestBody = {
      field_name: fieldName,
      type: fieldType,
      ...(property && { property })
    };

    req.write(JSON.stringify(requestBody));
    req.end();
  });
}

// 5. 创建记录
async function createRecord(token, appToken, tableId, fields) {
  return new Promise((resolve) => {
    const options = {
      hostname: 'open.feishu.cn',
      port: 443,
      path: `/open-apis/bitable/v1/apps/${appToken}/tables/${tableId}/records`,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${token}`
      },
    };

    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          if (json.code === 0) {
            resolve({ success: true, record: json.data?.record });
          } else {
            resolve({ success: false, error: json.msg });
          }
        } catch (error) {
          resolve({ success: false, error: error.message });
        }
      });
    });

    req.on('error', (error) => {
      resolve({ success: false, error: error.message });
    });

    req.write(JSON.stringify({ fields }));
    req.end();
  });
}

// 6. 主函数
async function main() {
  console.log('开始创建多维表格任务看板...\n');

  try {
    // 获取token
    console.log('1. 获取访问令牌...');
    const token = await getToken();
    console.log('✅ Token获取成功\n');

    // 创建Bitable应用
    const appName = `工作看板-任务管理-${new Date().toISOString().slice(0, 10)}`;
    const createResult = await createBitableApp(token, appName);

    if (!createResult.success) {
      console.log('❌ 多维表格创建失败');
      return;
    }

    const app = createResult.app;
    const appToken = app.app_token;

    // 等待一下
    await new Promise(resolve => setTimeout(resolve, 3000));

    // 获取表格列表
    const tablesResult = await getTables(token, appToken);
    if (!tablesResult.success || !tablesResult.tables || tablesResult.tables.length === 0) {
      console.log('❌ 无法获取表格列表');
      return;
    }

    // 使用第一个表格
    const firstTable = tablesResult.tables[0];
    const tableId = firstTable.table_id;
    console.log(`\n使用表格: ${firstTable.name} (ID: ${tableId})`);

    // 设计数据结构
    console.log('\n2. 设计数据结构...');

    // 任务表字段设计
    const taskFields = [
      { name: "任务ID", type: 1 }, // Text
      { name: "任务名称", type: 1 },
      { name: "状态", type: 3, property: { options: [{ name: "进行中" }, { name: "已完成" }] } }, // SingleSelect
      { name: "优先级", type: 3, property: { options: [{ name: "紧急" }, { name: "高" }, { name: "中" }, { name: "低" }] } },
      { name: "负责人", type: 1 },
      { name: "创建时间", type: 5 }, // DateTime
      { name: "预计完成", type: 5 },
      { name: "实际完成", type: 5 },
      { name: "耗时分钟", type: 2 }, // Number
      { name: "描述", type: 1 },
      { name: "产出", type: 1 },
      { name: "分类", type: 3, property: { options: [{ name: "技术开发" }, { name: "系统开发" }, { name: "项目管理" }] } }
    ];

    console.log(`任务表设计: ${taskFields.length} 个字段`);

    // 创建字段
    console.log('\n3. 创建字段...');
    let createdFields = 0;

    for (const field of taskFields) {
      const result = await createField(token, appToken, tableId, field.name, field.type, field.property);
      if (result.success) {
        createdFields++;
      }
      await new Promise(resolve => setTimeout(resolve, 500)); // 避免频率限制
    }

    console.log(`✅ 字段创建完成: ${createdFields}/${taskFields.length}`);

    // 插入任务数据
    console.log('\n4. 插入任务数据...');
    let insertedRecords = 0;

    for (const task of workspaceData.tasks) {
      const fields = {
        "任务ID": task.task_id,
        "任务名称": task.task_name,
        "状态": task.status,
        "优先级": task.priority,
        "负责人": task.owner,
        "创建时间": Date.parse(task.created_time),
        "预计完成": Date.parse(task.estimated_completion),
        "实际完成": task.actual_completion ? Date.parse(task.actual_completion) : null,
        "耗时分钟": task.time_spent_minutes,
        "描述": task.description,
        "产出": task.outputs,
        "分类": task.category
      };

      const result = await createRecord(token, appToken, tableId, fields);
      if (result.success) {
        insertedRecords++;
        console.log(`✅ 插入任务: ${task.task_name}`);
      } else {
        console.log(`❌ 插入失败: ${task.task_name} - ${result.error}`);
      }

      await new Promise(resolve => setTimeout(resolve, 500));
    }

    // 结果
    console.log('\n' + '='.repeat(50));
    console.log('🎉 多维表格任务看板创建完成!');
    console.log('='.repeat(50));
    console.log(`多维表格名称: ${app.name}`);
    console.log(`多维表格URL: ${app.url}`);
    console.log(`表格: ${firstTable.name}`);
    console.log(`字段创建: ${createdFields} 个`);
    console.log(`任务记录插入: ${insertedRecords} 条`);
    console.log('');
    console.log('🚀 现在可以:');
    console.log(`1. 打开多维表格: ${app.url}`);
    console.log('2. 查看自动填充的任务数据');
    console.log('3. 继续添加团队和统计数据');
    console.log('');
    console.log('💡 后续工作:');
    console.log('1. 创建团队表');
    console.log('2. 创建统计表');
    console.log('3. 建立自动化更新机制');

  } catch (error) {
    console.log('\n❌ 错误:', error.message);
  }
}

