// 4. 删除空记录
async function deleteEmptyRecords(token) {
  console.log('删除空记录...');

  // 先获取所有记录
  const recordsResult = await new Promise((resolve) => {
    const options = {
      hostname: 'open.feishu.cn',
      port: 443,
      path: `/open-apis/bitable/v1/apps/${APP_TOKEN}/tables/${TABLE_ID}/records`,
      method: 'GET',
      headers: {
        'Authorization': `Bearer ${token}`
      },
    };

    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          resolve(json);
        } catch (error) {
          resolve({ code: -1, msg: error.message });
        }
      });
    });

    req.on('error', (error) => {
      resolve({ code: -1, msg: error.message });
    });

    req.end();
  });

  if (recordsResult.code !== 0 || !recordsResult.data?.items) {
    console.log('获取记录失败:', recordsResult.msg);
    return 0;
  }

  const records = recordsResult.data.items;
  const emptyRecordIds = [];

  // 找出空记录（没有我们设计的字段数据）
  records.forEach(record => {
    if (!record.fields || Object.keys(record.fields).length === 0) {
      emptyRecordIds.push(record.record_id);
    } else {
      // 检查是否有我们设计的字段
      const hasOurFields = Object.keys(record.fields).some(fieldName => 
        KEEP_FIELDS.some(keepField => fieldName.includes(keepField))
      );

      if (!hasOurFields) {
        emptyRecordIds.push(record.record_id);
      }
    }
  });

  console.log(`找到 ${emptyRecordIds.length} 条空记录`);

  if (emptyRecordIds.length === 0) {
    return 0;
  }

  // 批量删除记录
  const deleteResult = await new Promise((resolve) => {
    const options = {
      hostname: 'open.feishu.cn',
      port: 443,
      path: `/open-apis/bitable/v1/apps/${APP_TOKEN}/tables/${TABLE_ID}/records/batch_delete`,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${token}`
      },
    };

    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          resolve(json);
        } catch (error) {
          resolve({ code: -1, msg: error.message });
        }
      });
    });

    req.on('error', (error) => {
      resolve({ code: -1, msg: error.message });
    });

    req.write(JSON.stringify({ records: emptyRecordIds }));
    req.end();
  });

  if (deleteResult.code === 0) {
    console.log(`✅ 删除 ${emptyRecordIds.length} 条空记录成功`);
    return emptyRecordIds.length;
  } else {
    console.log('❌ 批量删除失败:', deleteResult.msg);

    // 尝试逐个删除
    let deletedCount = 0;
    for (const recordId of emptyRecordIds) {
      const singleResult = await new Promise((resolve) => {
        const options = {
          hostname: 'open.feishu.cn',
          port: 443,
          path: `/open-apis/bitable/v1/apps/${APP_TOKEN}/tables/${TABLE_ID}/records/${recordId}`,
          method: 'DELETE',
          headers: {
            'Authorization': `Bearer ${token}`
          },
        };

        const req = https.request(options, (res) => {
          let data = '';
          res.on('data', (chunk) => data += chunk);
          res.on('end', () => {
            try {
              const json = JSON.parse(data);
              resolve(json);
            } catch (error) {
              resolve({ code: -1, msg: error.message });
            }
          });
        });

        req.on('error', (error) => {
          resolve({ code: -1, msg: error.message });
        });

        req.end();
      });

      if (singleResult.code === 0) {
        deletedCount++;
      }

      await new Promise(resolve => setTimeout(resolve, 200)); // 避免频率限制
    }

    console.log(`✅ 逐个删除 ${deletedCount} 条空记录成功`);
    return deletedCount;
  }
}

