// 5. 删除空记录
async function deleteEmptyRecords(token) {
  console.log('删除空记录...');

  const recordsResult = await new Promise((resolve) => {
    const options = {
      hostname: 'open.feishu.cn',
      port: 443,
      path: `/open-apis/bitable/v1/apps/${APP_TOKEN}/tables/${AGENTS_TABLE_ID}/records`,
      method: 'GET',
      headers: {
        'Authorization': `Bearer ${token}`
      },
    };

    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          resolve(json);
        } catch (error) {
          resolve({ code: -1, msg: error.message });
        }
      });
    });

    req.on('error', (error) => {
      resolve({ code: -1, msg: error.message });
    });

    req.end();
  });

  if (recordsResult.code !== 0 || !recordsResult.data?.items) {
    console.log('获取记录失败:', recordsResult.msg);
    return 0;
  }

  const records = recordsResult.data.items;
  const emptyRecordIds = records
    .filter(record => !record.fields || Object.keys(record.fields).length === 0)
    .map(record => record.record_id);

  console.log(`找到 ${emptyRecordIds.length} 条空记录`);

  if (emptyRecordIds.length === 0) {
    return 0;
  }

  const deleteResult = await new Promise((resolve) => {
    const options = {
      hostname: 'open.feishu.cn',
      port: 443,
      path: `/open-apis/bitable/v1/apps/${APP_TOKEN}/tables/${AGENTS_TABLE_ID}/records/batch_delete`,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${token}`
      },
    };

    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          resolve(json);
        } catch (error) {
          resolve({ code: -1, msg: error.message });
        }
      });
    });

    req.on('error', (error) => {
      resolve({ code: -1, msg: error.message });
    });

    req.write(JSON.stringify({ records: emptyRecordIds }));
    req.end();
  });

  if (deleteResult.code === 0) {
    console.log(`✅ 删除 ${emptyRecordIds.length} 条空记录成功`);
    return emptyRecordIds.length;
  } else {
    console.log('❌ 批量删除失败:', deleteResult.msg);
    return 0;
  }
}

