  const fields = fieldsResult.data.items;
  const defaultField = fields.find(f => f.field_name === "文本" && !f.is_primary);

  if (!defaultField) {
    console.log('没有找到可删除的默认字段');
    return true;
  }

  console.log(`找到默认字段: ${defaultField.field_name} (ID: ${defaultField.field_id})`);

  const deleteResult = await new Promise((resolve) => {
    const options = {
      hostname: 'open.feishu.cn',
      port: 443,
      path: `/open-apis/bitable/v1/apps/${APP_TOKEN}/tables/${SKILLS_TABLE_ID}/fields/${defaultField.field_id}`,
      method: 'DELETE',
      headers: {
        'Authorization': `Bearer ${token}`
      },
    };

    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          resolve(json);
        } catch (error) {
          resolve({ code: -1, msg: error.message });
        }
      });
    });

    req.on('error', (error) => {
      resolve({ code: -1, msg: error.message });
    });

    req.end();
  });

  if (deleteResult.code === 0) {
    console.log('✅ 默认字段删除成功');
    return true;
  } else {
    console.log('❌ 默认字段删除失败:', deleteResult.msg);
    return false;
  }
}

// 3. 创建字段
async function createField(token, fieldName, fieldType, property) {
  console.log(`创建字段: ${fieldName} (类型: ${fieldType})`);

  return new Promise((resolve) => {
    const options = {
      hostname: 'open.feishu.cn',
      port: 443,
      path: `/open-apis/bitable/v1/apps/${APP_TOKEN}/tables/${SKILLS_TABLE_ID}/fields`,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${token}`
      },
    };

    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          if (json.code === 0 && json.data && json.data.field) {
            console.log(`✅ 字段创建成功: ${fieldName}`);
            resolve({ success: true, field: json.data.field });
          } else {
            console.log(`❌ 字段创建失败: ${json.msg}`);
            resolve({ success: false, error: json.msg });
          }
        } catch (error) {
          console.log('JSON解析失败:', error.message);
          resolve({ success: false, error: error.message });
        }
      });
    });

    req.on('error', (error) => {
      console.log('请求错误:', error.message);
      resolve({ success: false, error: error.message });
    });

    const requestBody = {
      field_name: fieldName,
      type: fieldType,
      ...(property && { property })
    };

    req.write(JSON.stringify(requestBody));
    req.end();
  });
}

// 4. 创建记录
async function createRecord(token, fields) {
  return new Promise((resolve) => {
    const options = {
      hostname: 'open.feishu.cn',
      port: 443,
      path: `/open-apis/bitable/v1/apps/${APP_TOKEN}/tables/${SKILLS_TABLE_ID}/records`,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${token}`
      },
    };

    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          if (json.code === 0) {
            resolve({ success: true, record: json.data?.record });
          } else {
            resolve({ success: false, error: json.msg });
          }
        } catch (error) {
          resolve({ success: false, error: error.message });
        }
      });
    });

    req.on('error', (error) => {
      resolve({ success: false, error: error.message });
    });

    req.write(JSON.stringify({ fields }));
    req.end();
  });
}

// 5. 删除空记录
async function deleteEmptyRecords(token) {
  console.log('删除空记录...');

  const recordsResult = await new Promise((resolve) => {
    const options = {
      hostname: 'open.feishu.cn',
      port: 443,
      path: `/open-apis/bitable/v1/apps/${APP_TOKEN}/tables/${SKILLS_TABLE_ID}/records`,
      method: 'GET',
      headers: {
        'Authorization': `Bearer ${token}`
      },
    };

    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          resolve(json);
        } catch (error) {
          resolve({ code: -1, msg: error.message });
        }
      });
    });

    req.on('error', (error) => {
      resolve({ code: -1, msg: error.message });
    });

    req.end();
  });

  if (recordsResult.code !== 0 || !recordsResult.data?.items) {
    console.log('获取记录失败:', recordsResult.msg);
    return 0;
  }

  const records = recordsResult.data.items;
  const emptyRecordIds = records
    .filter(record => !record.fields || Object.keys(record.fields).length === 0)
    .map(record => record.record_id);

  console.log(`找到 ${emptyRecordIds.length} 条空记录`);

  if (emptyRecordIds.length === 0) {
    return 0;
  }

  const deleteResult = await new Promise((resolve) => {
    const options = {
      hostname: 'open.feishu.cn',
      port: 443,
      path: `/open-apis/bitable/v1/apps/${APP_TOKEN}/tables/${SKILLS_TABLE_ID}/records/batch_delete`,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${token}`
      },
    };

    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          resolve(json);
        } catch (error) {
          resolve({ code: -1, msg: error.message });
        }
      });
    });

    req.on('error', (error) => {
      resolve({ code: -1, msg: error.message });
    });

    req.write(JSON.stringify({ records: emptyRecordIds }));
    req.end();
  });

  if (deleteResult.code === 0) {
    console.log(`✅ 删除 ${emptyRecordIds.length} 条空记录成功`);
    return emptyRecordIds.length;
  } else {
    console.log('❌ 批量删除失败:', deleteResult.msg);
    return 0;
  }
}

