// 获取token
function getToken() {
  return new Promise((resolve) => {
    const options = {
      hostname: 'open.feishu.cn',
      port: 443,
      path: '/open-apis/auth/v3/tenant_access_token/internal',
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
    };

    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        const result = JSON.parse(data);
        resolve(result.tenant_access_token);
      });
    });

    req.write(JSON.stringify({ app_id: APP_ID, app_secret: APP_SECRET }));
    req.end();
  });
}

// 清空现有数据
async function clearExistingRecords(token) {
  console.log('清空现有Skills数据...');

  const recordsResult = await new Promise((resolve) => {
    const options = {
      hostname: 'open.feishu.cn',
      port: 443,
      path: `/open-apis/bitable/v1/apps/${APP_TOKEN}/tables/${SKILLS_TABLE_ID}/records`,
      method: 'GET',
      headers: {
        'Authorization': `Bearer ${token}`
      },
    };

    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          resolve(json);
        } catch (error) {
          resolve({ code: -1, msg: error.message });
        }
      });
    });

    req.on('error', (error) => {
      resolve({ code: -1, msg: error.message });
    });

    req.end();
  });

  if (recordsResult.code !== 0 || !recordsResult.data?.items) {
    console.log('获取记录失败:', recordsResult.msg);
    return 0;
  }

  const records = recordsResult.data.items;
  const recordIds = records.map(record => record.record_id);

  console.log(`找到 ${recordIds.length} 条现有记录`);

  if (recordIds.length === 0) {
    console.log('没有需要清空的记录');
    return 0;
  }

  const deleteResult = await new Promise((resolve) => {
    const options = {
      hostname: 'open.feishu.cn',
      port: 443,
      path: `/open-apis/bitable/v1/apps/${APP_TOKEN}/tables/${SKILLS_TABLE_ID}/records/batch_delete`,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${token}`
      },
    };

    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => data += chunk);
      res.on('end', () => {
        try {
          const json = JSON.parse(data);
          resolve(json);
        } catch (error) {
          resolve({ code: -1, msg: error.message });
        }
      });
    });

    req.on('error', (error) => {
      resolve({ code: -1, msg: error.message });
    });

    req.write(JSON.stringify({ records: recordIds }));
    req.end();
  });

  if (deleteResult.code === 0) {
    console.log(`✅ 清空 ${recordIds.length} 条记录成功`);
    return recordIds.length;
  } else {
    console.log('❌ 批量删除失败:', deleteResult.msg);
    return 0;
  }
}

